import{_ as t,c as o,o as a,a5 as i,f8 as n,f9 as s,fa as l,fb as r,fc as d,fd as c,fe as h,ff as p,fg as m,fh as u,fi as f,fj as b,fk as g,fl as k}from"./chunks/framework.Dm71djiW.js";const v=JSON.parse('{"title":"Slides","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guide-ppt.md","filePath":"docs/guide-ppt.md","lastUpdated":1772593260000}'),y={name:"docs/guide-ppt.md"};function w(_,e,x,P,S,q){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="slides" tabindex="-1">Slides <a class="header-anchor" href="#slides" aria-label="Permalink to “Slides”">​</a></h1><p><img src="'+n+'" alt=""></p><blockquote><p>PPT effect preview</p></blockquote><h2 id="related-operations" tabindex="-1">Related Operations <a class="header-anchor" href="#related-operations" aria-label="Permalink to “Related Operations”">​</a></h2><h3 id="enter-slide-mode" tabindex="-1">Enter Slide Mode <a class="header-anchor" href="#enter-slide-mode" aria-label="Permalink to “Enter Slide Mode”">​</a></h3><p><img src="'+s+'" alt=""></p><blockquote><p>Click <code>Style</code> -&gt; <code>beamer</code> in the focus toolbar to enter slide mode.</p></blockquote><h3 id="select-different-themes" tabindex="-1">Select Different Themes <a class="header-anchor" href="#select-different-themes" aria-label="Permalink to “Select Different Themes”">​</a></h3><p><img src="'+l+'" alt=""></p><blockquote><p>Use the focus toolbar to switch slide themes.</p></blockquote><h3 id="add-and-switch-pages" tabindex="-1">Add and Switch Pages <a class="header-anchor" href="#add-and-switch-pages" aria-label="Permalink to “Add and Switch Pages”">​</a></h3><p><img src="'+r+'" alt=""></p><blockquote><p>Use the focus toolbar to add slides and switch slides.</p></blockquote><h3 id="edit-text-math-enunciations-and-more" tabindex="-1">Edit Text, Math, Enunciations, and More <a class="header-anchor" href="#edit-text-math-enunciations-and-more" aria-label="Permalink to “Edit Text, Math, Enunciations, and More”">​</a></h3><p>This part is exactly the same as document editing. Please refer to the previous help docs.</p><h3 id="add-borders-to-theorem-and-other-enunciation-blocks" tabindex="-1">Add Borders to Theorem and Other Enunciation Blocks <a class="header-anchor" href="#add-borders-to-theorem-and-other-enunciation-blocks" aria-label="Permalink to “Add Borders to Theorem and Other Enunciation Blocks”">​</a></h3><p>First enter the enunciation block that needs background rendering, then click <code>Focus</code> -&gt; <code>Preferences</code> -&gt; <code>Theorem Border</code> in the toolbar. This adds a border to the enunciation block, making theorem-style environments visually independent from other text content. (The operation and before/after effect are shown below.) <img src="'+d+'" alt=""></p><h3 id="distinguish-folding-environments-and-layers" tabindex="-1">Distinguish Folding Environments and Layers <a class="header-anchor" href="#distinguish-folding-environments-and-layers" aria-label="Permalink to “Distinguish Folding Environments and Layers”">​</a></h3><ul><li><p>Insert a folding environment: <img src="'+c+'" alt=""></p></li><li><p>Insert a switch</p></li></ul><p>After inserting a <code>Switch</code> module and finishing content input on the first layer, you need to press <code>Alt</code> + <code>→</code>, or switch as shown below, to move to the second or even third layer so the effect takes place. <img src="'+h+'" alt=""></p><ul><li><p>Insert an unroll <img src="'+p+'" alt=""></p></li><li><p>Insert layers: In the menu bar, click <code>Insert</code> -&gt; <code>Fold</code> -&gt; <code>Layer</code> -&gt; <code>Standard</code>. You can insert multiple layers through structured insertion. When you click where the layer is located, the current layer indicator appears in the focus (current environment) toolbar, and you can switch layers directly.</p></li></ul><p>After creating layers, all content is shown by default. So if you want each layer to display only its own content, select the content in the layer to change, then click <code>Insert</code> -&gt; <code>Fold</code> -&gt; <code>Layer</code> -&gt; <code>Visable only here</code> in the menu bar to make it visible only in the current layer. You can also apply the same steps for other effects, for example: click <code>Insert</code> -&gt; <code>Fold</code> -&gt; <code>Layer</code> -&gt; <code>Visable from here on</code> to show content on the current and subsequent layers; click <code>Insert</code> -&gt; <code>Fold</code> -&gt; <code>Layer</code> -&gt; <code>Visable except here</code> to hide content only on the current layer.</p><p><img src="'+m+'" alt=""></p><blockquote><p>Effect demo: layers 1 and 2 set to <code>Visable only here</code>, layer 3 set to <code>Visable except here</code></p></blockquote><h2 id="how-to-present-slides" tabindex="-1">How to Present Slides <a class="header-anchor" href="#how-to-present-slides" aria-label="Permalink to “How to Present Slides”">​</a></h2><h3 id="page-turning" tabindex="-1">Page Turning <a class="header-anchor" href="#page-turning" aria-label="Permalink to “Page Turning”">​</a></h3><p><img src="'+u+'" alt=""></p><blockquote><p>The second button (PageDown) means next object rather than next page. It works like a presentation clicker and lets you move through consecutive next objects.</p></blockquote><h3 id="view-modes" tabindex="-1">View Modes <a class="header-anchor" href="#view-modes" aria-label="Permalink to “View Modes”">​</a></h3><p><img src="'+f+'" alt=""></p><blockquote><p>There are multiple modes in the View menu. When Focus Mode and Presentation Mode are enabled, the top menu bar and toolbar disappear. At this point, right-click and uncheck the selected mode to restore the default state.</p></blockquote><h3 id="how-to-export-slides" tabindex="-1">How to Export Slides <a class="header-anchor" href="#how-to-export-slides" aria-label="Permalink to “How to Export Slides”">​</a></h3><p>In the menu bar, click <code>Edit</code> -&gt; <code>Preferences</code> to open the user preferences window. Click <code>Convert</code> -&gt; <code>Pdf</code> and you will see a checkbox for expanding collapsible objects in slides. If it is not checked, exporting may turn one slide into multiple pages, as shown below:</p><p><img src="'+b+'" alt=""></p><blockquote><p>Export effect when &quot;expand collapsible objects in slides&quot; is not checked</p></blockquote><p><img src="'+g+'" alt=""></p><blockquote><p>Export effect when &quot;expand collapsible objects in slides&quot; is checked</p></blockquote><h2 id="free-ppt-styles-and-style-customization" tabindex="-1">Free PPT Styles and Style Customization <a class="header-anchor" href="#free-ppt-styles-and-style-customization" aria-label="Permalink to “Free PPT Styles and Style Customization”">​</a></h2><h3 id="styles-included-in-the-software" tabindex="-1">Styles Included in the Software <a class="header-anchor" href="#styles-included-in-the-software" aria-label="Permalink to “Styles Included in the Software”">​</a></h3><ul><li>Blackboard</li><li>Bluish</li><li>Boring-white</li><li>Dark-vador</li><li>Granite</li><li>Ice</li><li>Manila-paper</li><li>Metal</li><li>Pale-blue</li><li>Pine</li><li>Reddish</li><li>Ridged-paper</li><li>Rough-paper</li><li>Xperiment</li></ul><h3 id="free-styles-on-the-official-website" tabindex="-1">Free Styles on the Official Website <a class="header-anchor" href="#free-styles-on-the-official-website" aria-label="Permalink to “Free Styles on the Official Website”">​</a></h3><p>Go to the official website, click the docs library, scroll down to the slides section, click a template, then click download to get it. (Included templates are shown below.)</p><p><img src="'+k+'" alt=""></p><blockquote><p>Free styles on the official website</p></blockquote><h3 id="style-customization" tabindex="-1">Style Customization <a class="header-anchor" href="#style-customization" aria-label="Permalink to “Style Customization”">​</a></h3><p>After becoming a Fruit Member, you can customize one template each month. You can also purchase template customization services. For details, see <a href="./../pricing-template.html">Template Customization</a>.</p>',46)])])}const E=t(y,[["render",w]]);export{v as __pageData,E as default};
